package org.mage.test.cards.copy;

import mage.constants.PhaseStep;
import mage.constants.Zone;
import org.junit.Test;
import org.mage.test.serverside.base.CardTestPlayerBase;

/**
 * @author TheElk801
 */
public class EstridsInvocationTest extends CardTestPlayerBase {

    /**
     * Test that Estrid's Invocation can use its exile-and-return ability
     * multiple times when copying an aura enchantment.
     */
    @Test
    public void testCopyAuraMultipleTurns() {
        // Estrid's Invocation {2}{U}
        addCard(Zone.HAND, playerA, "Estrid's Invocation", 1);
        addCard(Zone.BATTLEFIELD, playerA, "Island", 3);

        // creature to enchant
        addCard(Zone.BATTLEFIELD, playerA, "Silvercoat Lion", 1);

        // Inferno Fist - aura enchantment
        // Enchant creature - Enchanted creature gets +2/+0.
        addCard(Zone.BATTLEFIELD, playerA, "Inferno Fist", 1);
        // Attach Inferno Fist to Silvercoat Lion
        addTarget(playerA, "Silvercoat Lion");

        // Turn 1 - cast Estrid's Invocation, copy Inferno Fist
        castSpell(1, PhaseStep.PRECOMBAT_MAIN, playerA, "Estrid's Invocation");
        setChoice(playerA, true); // use the copy effect
        setChoice(playerA, "Inferno Fist"); // choose enchantment to copy
        setChoice(playerA, "Silvercoat Lion"); // target for the copy aura

        // Turn 3 - first use of the triggered ability
        setChoice(playerA, true); // use the exile-and-return ability
        setChoice(playerA, true); // use the copy effect
        setChoice(playerA, "Inferno Fist"); // choose enchantment to copy
        setChoice(playerA, "Silvercoat Lion"); // target for the copy aura

        // Turn 5 - second use of the triggered ability (bug test)
        setChoice(playerA, true); // use the exile-and-return ability
        setChoice(playerA, true); // use the copy effect
        setChoice(playerA, "Inferno Fist"); // choose enchantment to copy
        setChoice(playerA, "Silvercoat Lion"); // target for the copy aura

        setStrictChooseMode(true);
        setStopAt(5, PhaseStep.BEGIN_COMBAT);
        execute();

        assertPermanentCount(playerA, "Inferno Fist", 2);
    }
}

