package org.mage.test.cards.copy;

import mage.constants.PhaseStep;
import mage.constants.Zone;
import org.junit.Test;
import org.mage.test.serverside.base.CardTestPlayerBase;

/**
 * @author TheElk801
 */
public class EstridsInvocationTest extends CardTestPlayerBase {

    /**
     * Test that Estrid's Invocation can use its exile-and-return ability
     * multiple times without causing a game error.
     *
     * Bug: Estrid's Invocation causes a fatal error when using its ability
     * in the second turn it's on the battlefield.
     */
    @Test
    public void testUseAbilityMultipleTurns() {
        // Estrid's Invocation {2}{U}
        addCard(Zone.HAND, playerA, "Estrid's Invocation", 1);
        addCard(Zone.BATTLEFIELD, playerA, "Island", 3);

        // Crucible of Fire - just a simple enchantment to copy
        addCard(Zone.BATTLEFIELD, playerA, "Crucible of Fire", 1);

        // Turn 1 (Player A) - cast Estrid's Invocation, copy Crucible of Fire
        castSpell(1, PhaseStep.PRECOMBAT_MAIN, playerA, "Estrid's Invocation");
        setChoice(playerA, true); // use the copy effect
        setChoice(playerA, "Crucible of Fire"); // choose enchantment to copy

        // Turn 3 (Player A) - first use of the triggered ability
        setChoice(playerA, true); // use the exile-and-return ability
        // After exile & return, choose to copy again
        setChoice(playerA, true); // use the copy effect
        setChoice(playerA, "Crucible of Fire"); // choose enchantment to copy

        // Turn 5 (Player A) - second use of the triggered ability (this was the bug)
        setChoice(playerA, true); // use the exile-and-return ability
        // After exile & return, choose to copy again
        setChoice(playerA, true); // use the copy effect
        setChoice(playerA, "Crucible of Fire"); // choose enchantment to copy

        setStrictChooseMode(true);
        setStopAt(5, PhaseStep.BEGIN_COMBAT);
        execute();

        // After copying Crucible of Fire, there should be one original + one copy = 2
        assertPermanentCount(playerA, "Crucible of Fire", 2);
    }
}

